def check(stdout: str) -> bool:
    import re
    def find(name):
        m = re.search(rf"\b{re.escape(name)}\b\s*=\s*([-+0-9.eE]+)", stdout, re.IGNORECASE)
        return float(m.group(1)) if m else None
    av_db = find("av_db")
    av_db_max = find("av_db_max")
    bw_hz = find("bw_hz")
    if av_db is None or av_db_max is None or bw_hz is None:
        return False
    # Spec 1: DC gain magnitude in [19.5, 20.5] dB
    if av_db < 19.5 or av_db > 20.5:
        return False
    # Spec 2: peak gain across band stays within upper bound (no peaking above 20.5 dB)
    if av_db_max > 20.5:
        return False
    # Spec 3: -3 dB bandwidth >= 500 kHz
    if bw_hz < 500e3:
        return False
    return True

import re

def check(stdout: str) -> bool:
    """Pass iff >=80% of PVT corners have AC gain at 1 kHz in [19.5, 20.5] dB."""
    pattern = re.compile(r'gain_c(\d+)\s*=\s*([-+]?\d*\.?\d+(?:[eE][-+]?\d+)?)', re.IGNORECASE)
    seen = {}
    for m in pattern.finditer(stdout):
        idx = int(m.group(1))
        try:
            val = float(m.group(2))
        except ValueError:
            continue
        # keep the last reported value for each corner index
        seen[idx] = val
    if len(seen) < 5:
        return False
    gains = list(seen.values())
    passes = sum(1 for g in gains if 19.5 <= g <= 20.5)
    return (passes / len(gains)) >= 0.8
